def main():
    for loop_name, rows in DATASETS.items():
        dir_path = Path("loops") / loop_name / "references"
        dir_path.mkdir(parents=True, exist_ok=True)
        dataset_path = dir_path / "dataset.jsonl"
        with open(dataset_path, "w", encoding="utf-8") as f:
            for row in rows:
                f.write(json.dumps(row) + "\n")
        print(f"Seeded {loop_name} with {len(rows)} hand-authored rows.")

if __name__ == "__main__":
    main()
